output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?date WHERE {
  {
    ?game wdt:P544 wd:Q16147495 ; wdt:P545 wd:Q6837710 ; wdt:P585 ?date
  } UNION {
    ?game wdt:P544 wd:Q6837710 ; wdt:P545 wd:Q16147495 ; wdt:P585 ?date
  }
  FILTER(?date > NOW ())
}
ORDER BY ASC(?date)
LIMIT 1

args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?date WHERE {
  { ?game wdt:P544 wd:Q16147495 ; # Notre Dame as home team
           wdt:P545 wd:Q6837710 ; # Michigan State as away team
           wdt:P585 ?date }
  UNION
  { ?game wdt:P544 wd:Q6837710 ; # Michigan State as home team
           wdt:P545 wd:Q16147495 ; # Notre Dame as away team
           wdt:P585 ?date }
}
ORDER BY ASC(?date)
LIMIT 10
